INSERT INTO "images" ("id","title","r2_keys","author","author_url","post_url","description","likes","created_at","updated_at","published","author_display_name") VALUES(6360,'@kyouko5477251 推文','kyouko5477251_1975398446627795232_1.webp,kyouko5477251_1975398446627795232_2.webp','kyouko5477251','https://x.com/kyouko5477251','https://x.com/kyouko5477251/status/1975398446627795232',replace(replace('唉我真的服了怎么什么事都能遇到\r\n推上有个加我的🚪之前给我打了1100块钱（虽然说前期还有部分但总之争议额度是这么多）说要买yw还有陪聊还有200是我找他借的以及400说是给我的生日礼物，但这人说话什么的让我感到十分的不安（大概就是非常狂热的想嫖我显然我不接受然后就开始各种闹以及千奇百怪的要求堪比论文查重）外加上各种吓唬我好多次，（我有医院确诊的焦虑症😇😇）总之行为非常困惑而且动不动超雄疯狂发怒让我对此十分的不安，所以说就想本着一种当断不断反受其乱的心态试图断联，然后掰扯了一晚上得出结论让我退600块钱，包括之前借来的200和这人说送我生日礼物但是要收回，然后再发一次快递寄东西，然后我把东西寄了之后，又退了600块钱（如图1）然后就给拉黑删好友了，但是这人发现我给他删了之后又对我切着不同的号进行言语羞辱，大概内容就是他给我少算500块钱就是为了留着我联系方式继续和我聊天（那我寻思着合着我东西就免费送呗）但是我给删了就要找我要剩下500块钱（可能是我当时为了防止这人又发怒暴起然后说的柔和很多但是我寻思着我意思都到这步了大家都应该知道我想表达什么吧）不过总之就是事情就是这样，所以我对此表示十分的不安和困惑，也不知道这人之后会打算继续骚扰我还是换着方法报复我之类的，也实在不好意思给大家看这么不友善的内容🙇🏻‍♀️🙇🏻‍♀️实在是抱歉给大家添麻烦了，总之决定最近先断更几天🙏🏻🙏🏻最后再次抱歉打扰到大家的兴致了🥺以上↑','\r',char(13)),'\n',char(10)),0,'2025-10-07T03:11:05',NULL,1,'きょうこ🐰（邪恶版）');
