INSERT INTO "images" ("id","title","r2_keys","author","author_url","post_url","description","likes","created_at","updated_at","published","author_display_name") VALUES(10339,'@tsukiha3himizu 推文','tsukiha3himizu_2051546618780897340_1.webp','tsukiha3himizu','https://x.com/tsukiha3himizu','https://x.com/tsukiha3himizu/status/2051546618780897340',replace(replace('睡前回答一波提问\r\n1. 开组会 改代码 健身 可能拍点新图\r\n2. 修图的时候偶尔会，但是我不觉得那个是真的自己\r\n3. 感谢厚爱，之后也会继续建设ansy\r\n4. 很难讲，我年龄太大已经出脑了（当你比动画里姐系角色都大一圈的时候）\r\n肉体层面可能还是甘雨吧，羊角和魅魔是我xp；邦多利也算二游的话那就是爱音；其实也很喜欢pcr的凯露和优妮但是有点时代眼泪了；BA我只能说本子都挺好用的。二游的人物塑造多少都有点……\r\n\r\n提问箱：https://ngl.link/tsukiha3himzu','\r',char(13)),'\n',char(10)),0,'2026-05-05T06:16:44',NULL,1,'月羽Tsukiha');
