INSERT INTO "images" ("id","title","r2_keys","author","author_url","post_url","description","likes","created_at","updated_at","published","author_display_name") VALUES(10345,'@tsukiha3himizu 推文','tsukiha3himizu_2050845310541262911_1.webp','tsukiha3himizu','https://x.com/tsukiha3himizu','https://x.com/tsukiha3himizu/status/2050845310541262911',replace(replace('Day 40\r\n你们已经去了CP/星铁LAND/方舟音律联觉/萤火虫/AM03/CGF/世界线了吧，那种我从来没去过的高级地方，领着我从来没领过的无料，和帅气的coser老师们集邮。我今天捡的垃圾，刚好够买你喜欢的谷子，你的房间我也全部打扫干净了，今天晚上还回来吗？我会给你准备一大桌好吃的饭，我累了就先睡觉了，会给你留门的，不用担心我一个人在家挺好的。你玩的开心就好了，不用在意我，真的。','\r',char(13)),'\n',char(10)),0,'2026-05-03T07:49:59',NULL,1,'月羽Tsukiha');
