INSERT INTO "images" ("id","title","r2_keys","author","author_url","post_url","description","likes","created_at","updated_at","published","author_display_name") VALUES(10368,'@tsukiha3himizu 推文','tsukiha3himizu_2061661989168910622_1.webp','tsukiha3himizu','https://x.com/tsukiha3himizu','https://x.com/tsukiha3himizu/status/2061661989168910622',replace(replace('攒了很久回复一波提问（顺序从左到右从上到下）\r\n提问箱链接：https://ngl.link/tsukiha3himzu\r\n1. 应该是不会？毕竟我在美国大农村又暂时回不了国，长期网恋也不会有什么意义\r\n2. 线下认识过的人里完全没有，网友大概有一个，和TA聊天比较自在 不过也不是恋爱意义上那种喜欢\r\n3. 谢谢~被人夸赞还是挺开心的不过毕竟是不露脸 露脸就全完了🥲\r\n4. 大概吧\r\n5. 单身 而且估计单到成为大魔法师（毕业都29了）\r\n6. 有人喜欢看透光的 有人喜欢看油光的 众口难调啊 只能说主播不会一直发很重复的东西 都会轮到的\r\n7. 那你想吧，反正想想不会给人造成困扰，说出来就未必了\r\n8. 所以那个人是你吗？我唯一确定爱我的人大概也就父母（虽然这个号绝对不能让他们知道\r\n9. 梦想是成为科学家（棒读）和财富自由以后天天发展兴趣爱好。不过虽然已经认定自己做不了纯科学研究，大概还是能成为偏工程的科研民工的','\r',char(13)),'\n',char(10)),0,'2026-06-02T04:11:36',NULL,1,'月羽Tsukiha');
