INSERT INTO "images" ("id","title","r2_keys","author","author_url","post_url","description","likes","created_at","updated_at","published","author_display_name") VALUES(10385,'@tsukiha3himizu 推文','tsukiha3himizu_2064680656152478150_1.webp','tsukiha3himizu','https://x.com/tsukiha3himizu','https://x.com/tsukiha3himizu/status/2064680656152478150',replace(replace('Day 78\r\n澄清下关于上一条“凭准考证免费一次”\r\n本意是趁着各地高考结束翻拍某张AI生成的梗图。主播目前算是定居美国且几年内不会回国。本账号没有任何收费项目，之前所有cos照片都在我的个人资料中，所以大概是本来就免费……\r\n总之祝高考结束的朋友们假期快乐！不要再给我发准考证了，注意个人信息安全','\r',char(13)),'\n',char(10)),0,'2026-06-10T12:06:42',NULL,1,'月羽Tsukiha');
